#!/usr/bin/env bash
# FORGE forge-parity — single-source generator entry point (Spec 480 / NC-1a).
#
# The repo-root tree is the single canonical source. Both downstream surfaces —
# the plugin payload (.claude/commands/, generated by forge-sync-commands.sh) and
# the template/ Copier surface (generated by forge-sync-cross-level.sh) — are
# rendered artifacts. This is a THIN WRAP: it delegates generation and drift
# checking to the two existing scripts and never reimplements their logic.
#
# Usage:
#   forge-parity.sh           Regenerate all downstream surfaces from canonical.
#   forge-parity.sh --check   Verify no drift; non-zero exit if EITHER surface drifted.
#   forge-parity.sh -h|--help Show this help.
#
# Per-script equality semantics (Spec 480 Req 2):
#   - .claude/commands/ mirrors: body-equivalence (Spec 329 frontmatter-aware).
#   - cross-level cp mirrors:     byte-equivalence over the common subset.
#   - .jinja Copier-var files:    excluded (Spec 281/390).
#
# Exit codes:
#   0 = success (generate completed, or --check found no drift)
#   1 = drift detected (--check) or argument error
set -euo pipefail

# Resolve script dir robustly so this works from any CWD.
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
SYNC_COMMANDS="${SCRIPT_DIR}/forge-sync-commands.sh"
SYNC_CROSS_LEVEL="${SCRIPT_DIR}/forge-sync-cross-level.sh"
SYNC_SKILLS="${SCRIPT_DIR}/forge-sync-skills.sh"  # Spec 491 — .claude/skills generator

CHECK_MODE=false

while [[ $# -gt 0 ]]; do
  case "$1" in
    --check)
      CHECK_MODE=true
      shift
      ;;
    -h|--help)
      cat <<'HELP'
Usage: forge-parity.sh [--check]

Single-source generator entry point (Spec 480 / NC-1a). Repo-root is the canonical
source; .claude/commands/ and template/ are downstream generated artifacts.

  (no flags)  Regenerate all downstream surfaces from the canonical source by
              running forge-sync-commands.sh then forge-sync-cross-level.sh.
  --check     Run both scripts' --check modes; exit non-zero if EITHER surface
              has drifted, naming which surface drifted. Bounded runtime — this
              only delegates to the existing O(tracked-files) --check modes
              (no Copier re-render).
  -h, --help  Show this help.

This is a thin wrap: it does NOT reimplement generation. Generation logic lives
in forge-sync-commands.sh (.claude/commands/) and forge-sync-cross-level.sh
(template/ mirrors), which it must not modify.
HELP
      exit 0
      ;;
    *)
      echo "ERROR: Unknown argument: $1" >&2
      echo "Run 'forge-parity.sh --help' for usage." >&2
      exit 1
      ;;
  esac
done

# Sanity: all delegate scripts must be present.
for script in "$SYNC_COMMANDS" "$SYNC_CROSS_LEVEL" "$SYNC_SKILLS"; do
  if [[ ! -f "$script" ]]; then
    echo "ERROR: Required sync script not found: $script" >&2
    exit 1
  fi
done

if $CHECK_MODE; then
  echo "## forge-parity --check (Spec 480 / NC-1a)"
  echo ""
  DRIFT_SURFACES=()

  echo "=== Surface 1: .claude/commands/ (forge-sync-commands.sh --check) ==="
  if bash "$SYNC_COMMANDS" --check; then
    echo "  parity: OK"
  else
    DRIFT_SURFACES+=(".claude/commands/ (forge-sync-commands.sh)")
  fi
  echo ""

  echo "=== Surface 2: template/ mirrors (forge-sync-cross-level.sh --check) ==="
  # Capture cross-level output so we can surface Spec 481 stale-mirror WARNs at
  # the parity level. WARNs are advisory (cross-level exits 0 on WARN-only), so
  # they do not flip the parity result, but they must remain visible here.
  CROSS_OUT="$(bash "$SYNC_CROSS_LEVEL" --check)" && CROSS_RC=0 || CROSS_RC=$?
  echo "$CROSS_OUT"
  if [[ ${CROSS_RC} -eq 0 ]]; then
    echo "  parity: OK"
    if echo "$CROSS_OUT" | grep -q '^WARN \[stale-mirror\]:'; then
      echo "  NOTE: advisory stale-mirror WARN(s) present above (Spec 481) — drift-listed canonical changed while mirror stale; review and regenerate or accept."
    fi
  else
    DRIFT_SURFACES+=("template/ mirrors (forge-sync-cross-level.sh)")
  fi
  echo ""

  # Surface 3 (Spec 489 / SIG-487-02): .forge/{bin,lib} canonical <-> template mirror parity.
  # forge-sync-cross-level only covers .forge/commands, .claude/agents, docs/process-kit — it does
  # NOT cover .forge/{bin,lib}, so those could silently drift. This surface closes that gap.
  # CR-normalized compare (.ps1 mirrors materialize CRLF on Windows checkouts; Spec 482 convention).
  echo "=== Surface 3: .forge/{bin,lib} mirrors (Spec 489 / SIG-487-02) ==="
  PARITY_ROOT="$(cd "${SCRIPT_DIR}/../.." && pwd)"
  FORGE_DIR_DRIFT=0
  # Spec 554: batch the CR-normalized compares into ONE forge-py process — the
  # per-file `diff <(tr ...)` form spawned ~5 processes x ~85 files (~60s of
  # win32 sys time). Identical semantics: same globs, same missing-mirror and
  # differs messages, CR-stripped byte equality. Falls back to the original
  # per-file loop when forge-py is unavailable.
  if [ -x "${PARITY_ROOT}/.forge/bin/forge-py" ] || command -v python3 >/dev/null 2>&1; then
    _drift_out="$("${PARITY_ROOT}/.forge/bin/forge-py" - "$PARITY_ROOT" <<'PYEOF'
import glob, os, sys
root = sys.argv[1]
drift = 0
files = []
for pat in (".forge/bin/*.sh", ".forge/bin/*.ps1", ".forge/lib/*.sh", ".forge/lib/*.ps1"):
    files.extend(glob.glob(os.path.join(root, pat)))
for cf in sorted(files):
    if not os.path.isfile(cf):
        continue
    rel = os.path.relpath(cf, root).replace(os.sep, "/")
    mirror = os.path.join(root, "template", rel)
    if not os.path.isfile(mirror):
        print(f"  DRIFT: missing mirror template/{rel}")
        drift = 1
        continue
    with open(cf, "rb") as fa, open(mirror, "rb") as fb:
        if fa.read().replace(b"\r", b"") != fb.read().replace(b"\r", b""):
            print(f"  DRIFT: {rel} differs from its template mirror")
            drift = 1
sys.exit(drift)
PYEOF
)" && FORGE_DIR_DRIFT=0 || FORGE_DIR_DRIFT=1
    if [ -n "${_drift_out}" ]; then printf '%s\n' "${_drift_out}"; fi
  else
    for _cf in "${PARITY_ROOT}"/.forge/bin/*.sh "${PARITY_ROOT}"/.forge/bin/*.ps1 "${PARITY_ROOT}"/.forge/lib/*.sh "${PARITY_ROOT}"/.forge/lib/*.ps1; do
      [ -f "$_cf" ] || continue
      _rel="${_cf#"${PARITY_ROOT}"/}"
      _mirror="${PARITY_ROOT}/template/${_rel}"
      if [ ! -f "$_mirror" ]; then
        echo "  DRIFT: missing mirror template/${_rel}"
        FORGE_DIR_DRIFT=1
        continue
      fi
      if ! diff <(tr -d '\r' < "$_cf") <(tr -d '\r' < "$_mirror") >/dev/null 2>&1; then
        echo "  DRIFT: ${_rel} differs from its template mirror"
        FORGE_DIR_DRIFT=1
      fi
    done
  fi
  if [ "$FORGE_DIR_DRIFT" -eq 0 ]; then
    echo "  parity: OK"
  else
    DRIFT_SURFACES+=(".forge/{bin,lib} mirrors (Spec 489)")
  fi
  echo ""

  # Surface 4 (Spec 490): plugin.json manifest schema — agents are files, no enumeration drift.
  echo "=== Surface 4: plugin.json manifest schema (Spec 490) ==="
  if bash "${SCRIPT_DIR}/check-plugin-manifest.sh" >/dev/null 2>&1; then
    echo "  schema: OK"
  else
    echo "  schema: FAIL (run .forge/bin/check-plugin-manifest.sh for detail)"
    DRIFT_SURFACES+=("plugin.json manifest schema (Spec 490)")
  fi
  echo ""

  # Surface 5 (Spec 491): .claude/skills generated from canonical + invocation-policy.yaml.
  # Two gates: (a) --check proves the skill tree matches the canonical-generated output
  # (drift gate, closes the hand-maintained-divergence class); (b) --verify-policy proves
  # the level-invariant disable-model-invocation classification (AC9 safety gate).
  echo "=== Surface 5: .claude/skills (forge-sync-skills.sh --check) ==="
  if bash "$SYNC_SKILLS" --check; then
    echo "  parity: OK"
  else
    DRIFT_SURFACES+=(".claude/skills (forge-sync-skills.sh)")
  fi
  if bash "$SYNC_SKILLS" --verify-policy; then
    echo "  policy: OK"
  else
    DRIFT_SURFACES+=(".claude/skills invocation-policy (forge-sync-skills.sh --verify-policy)")
  fi
  echo ""

  # Surface 6 (Spec 524): consensus-classifier single-source parity. The workflow
  # script embeds a duplicated copy of the divergence classifier (Workflow scripts
  # cannot import at runtime); this gate byte-verifies it against the canonical
  # .forge/lib/consensus-classifier.js. Skip silently if the artifacts are absent
  # (consumer projects predating Spec 524).
  if [ -f "${SCRIPT_DIR}/check-consensus-classifier-parity.sh" ] && [ -f "${SCRIPT_DIR}/../workflows/consensus.workflow.js" ]; then
    echo "=== Surface 6: consensus-classifier single source (Spec 524) ==="
    if bash "${SCRIPT_DIR}/check-consensus-classifier-parity.sh"; then
      : # OK line printed by the check
    else
      DRIFT_SURFACES+=("consensus-classifier embed (Spec 524 — .forge/workflows/consensus.workflow.js)")
    fi
    echo ""
  fi

  echo "## Summary"
  if [[ ${#DRIFT_SURFACES[@]} -eq 0 ]]; then
    echo "PASS: canonical source and all generated surfaces are in sync."
    exit 0
  else
    echo "FAILED: drift detected on ${#DRIFT_SURFACES[@]} surface(s):"
    for surface in "${DRIFT_SURFACES[@]}"; do
      echo "  - $surface"
    done
    echo ""
    echo "Run '.forge/bin/forge-parity.sh' (no flags) to regenerate downstream surfaces from canonical."
    exit 1
  fi
fi

# --- Generate mode (default): regenerate all downstream surfaces from canonical ---
echo "## forge-parity (generate — regenerate downstream from canonical source)"
echo ""
echo "=== Surface 1: .claude/commands/ (forge-sync-commands.sh) ==="
bash "$SYNC_COMMANDS"
echo ""
echo "=== Surface 2: template/ mirrors (forge-sync-cross-level.sh) ==="
bash "$SYNC_CROSS_LEVEL"
echo ""
echo "=== Surface 5: .claude/skills (forge-sync-skills.sh) ==="
bash "$SYNC_SKILLS"
echo ""
echo "## forge-parity — generation complete."
